<#
.SYNOPSIS
  VCF 9.1 ESX Validation and JSON Generator v41 Production

.DESCRIPTION
  Production WPF tool for ESX readiness remediation/validation and bulk commission JSON generation.



  v41 updates:
  - Switched required PowerCLI rollup module to VCF.PowerCLI.
  - Updated prerequisite detection, import, error messaging, and install button command for VCF.PowerCLI.

  v40 included fixes:
  - Restores dark production UI layout/styling.
  - Separates Hostname/DNS/Domain Set from Hostname/DNS/Domain Verify.
  - DNS verify accepts functional DNS query success if ESX DNS-list parsing is blank.
  - Adds SSH retry wrapper for ESX shell commands.
  - Sets/verifies DNS, hostname/FQDN, domain/search suffix, NTP, NTP service, time drift, certificate lowercase FQDN, vSAN, ESX version.
  - Enforces IPv6 disabled when Apply remediation is checked and reports Remediated / pending reboot.
  - Disables SSH and sends final reboot request. Reboot acknowledgement warnings are expected when management drops.
#>
[CmdletBinding()]
param()
$ErrorActionPreference='Stop'
[Net.ServicePointManager]::SecurityProtocol=[Net.SecurityProtocolType]::Tls12
$script:PowerCliModule='VCF.PowerCLI'
try{if(Get-Module -ListAvailable -Name $script:PowerCliModule){Import-Module $script:PowerCliModule -ErrorAction Stop|Out-Null;Set-PowerCLIConfiguration -InvalidCertificateAction Ignore -Confirm:$false -Scope User|Out-Null}}catch{}
Add-Type -AssemblyName PresentationFramework,PresentationCore,WindowsBase,System.Xaml
$script:RunDir=Join-Path (Get-Location) ("VCF91-Validation-Json-Run-"+(Get-Date -Format yyyyMMdd-HHmmss));New-Item -ItemType Directory -Path $script:RunDir -Force|Out-Null
$script:LogFile=Join-Path $script:RunDir ("ValidationJson-"+(Get-Date -Format yyyyMMdd-HHmmss)+'.log')
$script:IsRunning=$false;$script:StopRequested=$false;$script:LastReportPath=$null;$script:CurrentShellUser=$null;$script:CurrentShellPassword=$null
function DoEvents{try{[System.Windows.Threading.Dispatcher]::CurrentDispatcher.Invoke([Action]{},[System.Windows.Threading.DispatcherPriority]::Background)}catch{}}
function Log([string]$m,[string]$l='INFO'){$line="$(Get-Date -Format 'yyyy-MM-dd HH:mm:ss.fff') [$l] $m";Add-Content -Path $script:LogFile -Value $line;if($script:txtLog){$script:txtLog.AppendText($line+[Environment]::NewLine);$script:txtLog.ScrollToEnd();DoEvents}}
function HasMod($n){[bool](Get-Module -ListAvailable -Name $n)};function Imp($n){Import-Module $n -ErrorAction Stop}
function Cred($u,$p){New-Object pscredential($u,(ConvertTo-SecureString $p -AsPlainText -Force))}
function SafeLower($v){if($null -eq $v){''}else{([string]$v).Trim().ToLowerInvariant()}}
function SplitList([string]$t){@($t -split '[,;\s]+'|Where-Object{$_ -and $_.Trim()}|ForEach-Object{$_.Trim()})}
function Norm($items){@($items|Where-Object{$_ -and ([string]$_).Trim()}|ForEach-Object{([string]$_).Trim().ToLowerInvariant()}|Sort-Object -Unique)}
function EqualList($a,$b){$x=@(Norm $a);$y=@(Norm $b);if($x.Count-ne$y.Count){return $false};foreach($i in $x){if($y -notcontains $i){return $false}};return $true}
function ContainsAll($desired,$actual){$d=@(Norm $desired);$a=@(Norm $actual);foreach($i in $d){if($a -notcontains $i){return $false}};return $true}
function Check($s,$d){[pscustomobject]@{Status=$s;Detail=$d}}
function PassLike($s){$s -match '^(Pass|Remediated|N/A)$'}
function CheckStop{if($script:StopRequested){throw 'Stop requested by operator.'}}
function SleepUi($sec){$e=(Get-Date).AddSeconds($sec);while((Get-Date)-lt$e){DoEvents;Start-Sleep -Milliseconds 250}}
function Q([string]$s){"'"+($s -replace "'","'\\''")+"'"}
function WaitTcp($h,$p,$sec){$e=(Get-Date).AddSeconds($sec);while((Get-Date)-lt$e){try{$c=New-Object Net.Sockets.TcpClient;$r=$c.BeginConnect($h,$p,$null,$null);if($r.AsyncWaitHandle.WaitOne(900,$false)){$c.EndConnect($r);$c.Close();return $true};$c.Close()}catch{};SleepUi 1};$false}
function VerCmp($a,$b){try{([version]$a).CompareTo([version]$b)}catch{[string]::Compare($a,$b,$true)}}
function EnsureToolSelfSignedCertificate{try{if($IsWindows -and (Get-Command New-SelfSignedCertificate -ErrorAction SilentlyContinue)){$sub='CN=VCF91-ESX-Validation-JSON-Generator';$cert=Get-ChildItem Cert:\CurrentUser\My -ErrorAction SilentlyContinue|Where-Object{$_.Subject -eq $sub}|Select-Object -First 1;if(!$cert){New-SelfSignedCertificate -Subject $sub -CertStoreLocation Cert:\CurrentUser\My -KeyLength 2048 -NotAfter (Get-Date).AddYears(3)|Out-Null;Log 'Generated local self-signed certificate for tool launch context.'}else{Log 'Local tool self-signed certificate already present.'}}}catch{Log "Local tool certificate generation warning: $($_.Exception.Message)" WARN}}
function TargetRows{try{$null=$gridValidation.CommitEdit();$null=$gridValidation.CommitEdit([System.Windows.Controls.DataGridEditingUnit]::Row,$true)}catch{};$rows=@();foreach($x in @($script:Targets)){$h=([string]$x.TargetHost).Trim();if(!$h){continue};$u=if([string]::IsNullOrWhiteSpace([string]$x.Username)){'root'}else{([string]$x.Username).Trim()};$rows+=[pscustomobject]@{TargetHost=(SafeLower $h);Username=$u;Password=[string]$x.Password}};@($rows)}
function ValidateInputs{$m=@();if([string]::IsNullOrWhiteSpace($txtDns.Text)){$m+='DNS servers'};if([string]::IsNullOrWhiteSpace($txtNtp.Text)){$m+='NTP servers'};if([string]::IsNullOrWhiteSpace($txtDomains.Text)){$m+='Search domains'};if($m.Count){throw 'Populate required Desired ESX Configuration field(s): '+($m -join ', ')};if(@(TargetRows).Count -eq 0){throw 'Add at least one host.'}}
function Prereq{$lblPS.Text=$PSVersionTable.PSVersion.ToString();$lblPS.Foreground='LightGreen';$pcliFound=HasMod $script:PowerCliModule;$lblPCLI.Text=if($pcliFound){'Found'}else{'Missing'};$lblPCLI.Foreground=if($pcliFound){'LightGreen'}else{'Tomato'};$lblExcel.Text=if(HasMod ImportExcel){'Found'}else{'Missing'};$lblExcel.Foreground=if(HasMod ImportExcel){'LightGreen'}else{'Tomato'};$lblSsh.Text=if(HasMod Posh-SSH){'Found'}else{'Missing'};$lblSsh.Foreground=if(HasMod Posh-SSH){'LightGreen'}else{'Tomato'}}
function ConnectRetry($h,$u,$p){if(!(HasMod $script:PowerCliModule)){throw 'VCF.PowerCLI module is required. Use the Install VCF PowerCLI button or run: Install-Module -Name VCF.PowerCLI -Scope CurrentUser -Force -AllowClobber -SkipPublisherCheck'};Imp $script:PowerCliModule|Out-Null;try{Set-PowerCLIConfiguration -InvalidCertificateAction Ignore -Confirm:$false -Scope User|Out-Null}catch{};for($i=1;$i-le3;$i++){try{Log "[$h] Connect-VIServer attempt $i of 3...";return Connect-VIServer -Server $h -Credential (Cred $u $p) -Force -ErrorAction Stop}catch{Log "[$h] Connect failed attempt $i of 3: $($_.Exception.Message)" WARN;if($i-lt3){SleepUi 5}else{throw}}}}
function MgmtIp($vmh){try{$v=Get-VMHostNetworkAdapter -VMHost $vmh -VMKernel|Where-Object{$_.ManagementTrafficEnabled}|Select-Object -First 1;if($v.IP){return [string]$v.IP}}catch{};return $vmh.Name}
function EnableSsh($vmh){try{$svc=Get-VMHostService -VMHost $vmh|Where-Object{$_.Key -eq 'TSM-SSH'}|Select-Object -First 1;if($svc -and !$svc.Running){Log "[$($vmh.Name)] Starting SSH service for readiness commands..." WARN;Start-VMHostService -HostService $svc -Confirm:$false|Out-Null;SleepUi 6}}catch{Log "[$($vmh.Name)] SSH start warning: $($_.Exception.Message)" WARN}}
function SshRun($h,$u,$p,$cmd,$to=120){if(!(HasMod Posh-SSH)){throw 'Posh-SSH module is required.'};Imp Posh-SSH|Out-Null;$s=$null;$old=$WarningPreference;try{if(!(WaitTcp $h 22 25)){throw 'TCP/22 not reachable.'};$WarningPreference='SilentlyContinue';$s=New-SSHSession -ComputerName $h -Credential (Cred $u $p) -AcceptKey -Force -ConnectionTimeout 15 -WarningAction SilentlyContinue -ErrorAction Stop;$r=Invoke-SSHCommand -SessionId $s.SessionId -Command $cmd -TimeOut $to -ErrorAction Stop;[pscustomobject]@{StdOut=(@($r.Output)-join"`n");StdErr=(@($r.Error)-join"`n");ExitStatus=$r.ExitStatus}}finally{$WarningPreference=$old;if($s){try{Remove-SSHSession -SessionId $s.SessionId|Out-Null}catch{}}}}
function Esx($vmh,$cmd,$to=120){SshRun (MgmtIp $vmh) $script:CurrentShellUser $script:CurrentShellPassword $cmd $to}
function EsxRetry($vmh,$cmd,$to=120,$tries=4){$last='';for($i=1;$i-le$tries;$i++){try{if($i-gt1){Log "[$($vmh.Name)] ESX shell retry $i of $tries..." WARN;EnableSsh $vmh;SleepUi 5};return Esx $vmh $cmd $to}catch{$last=$_.Exception.Message;Log "[$($vmh.Name)] ESX shell attempt $i failed: $last" WARN;if($i-lt$tries){SleepUi 8}}};throw $last}
function DisableSsh($vmh){try{Esx $vmh '(vim-cmd hostsvc/disable_ssh >/dev/null 2>&1 || true); (/etc/init.d/SSH stop || /etc/init.d/TSM-SSH stop || /etc/init.d/ssh stop || true)' 30|Out-Null}catch{};try{$svc=Get-VMHostService -VMHost $vmh|Where-Object{$_.Key -eq 'TSM-SSH'}|Select-Object -First 1;if($svc){Set-VMHostService -HostService $svc -Policy Off -ErrorAction SilentlyContinue|Out-Null;if($svc.Running){Stop-VMHostService -HostService $svc -Confirm:$false -ErrorAction SilentlyContinue|Out-Null}};Log "[$($vmh.Name)] SSH service stopped/disabled after readiness."}catch{Log "[$($vmh.Name)] SSH disable warning: $($_.Exception.Message)" WARN}}
function RebootHost($vmh,$h){try{Log "[$h] Reboot request sent after SSH disable. Management may drop before acknowledgement; warning is expected during reboot." WARN;Restart-VMHost -VMHost $vmh -Force -Confirm:$false -ErrorAction Stop|Out-Null;SleepUi 10}catch{Log "[$h] Reboot request warning: management connection likely dropped during reboot acknowledgement: $($_.Exception.Message)" INFO}}
function SetHostDns($vmh,$fqdn,$dnsTxt,$domTxt,$apply){$desiredDns=SplitList $dnsTxt;$domain=(SplitList $domTxt|Select-Object -First 1);$short=($fqdn -split '\.')[0];if(!$apply){return Check 'N/A' 'Apply remediation is disabled; hostname/DNS/domain set skipped.'};try{Log "[$fqdn] Setting hostname/FQDN/domain/DNS. Host=$short Domain=$domain DNS=$(($desiredDns -join ','))";$powerCliOk=$false;$powerCliMsg='';try{$net=Get-VMHostNetwork -VMHost $vmh -ErrorAction Stop;Set-VMHostNetwork -Network $net -HostName $short -DomainName $domain -DnsAddress $desiredDns -ErrorAction Stop|Out-Null;$powerCliOk=$true}catch{$powerCliMsg=$_.Exception.Message;Log "[$fqdn] PowerCLI DNS set warning: $powerCliMsg. Applying ESX shell set/confirmation." WARN};$add=($desiredDns|ForEach-Object{"esxcli network ip dns server add -s $(Q $_) >/dev/null 2>&1 || true"}) -join "`n";$cmd=@'
esxcli system hostname set --host=__SHORT__ --domain=__DOMAIN__ --fqdn=__FQDN__ || true
for s in $(esxcli network ip dns server list 2>/dev/null | awk '/^[0-9]/{print $1}'); do esxcli network ip dns server remove -s $s >/dev/null 2>&1 || true; done
__ADD__
esxcli network ip dns search add -d __DOMAIN__ >/dev/null 2>&1 || true
'@;$cmd=$cmd.Replace('__SHORT__',(Q $short)).Replace('__DOMAIN__',(Q $domain)).Replace('__FQDN__',(Q $fqdn)).Replace('__ADD__',$add);EsxRetry $vmh $cmd 120 4|Out-Null;SleepUi 3;return Check 'Remediated' "Set requested. PowerCLISet=$powerCliOk; PowerCLIMessage=$powerCliMsg; DesiredHost=$short; DesiredFQDN=$fqdn; DesiredDomain=$domain; DesiredDNS=$(($desiredDns-join ','))"}catch{return Check 'Fail' $_.Exception.Message}}
function VerifyHostDns($vmh,$fqdn,$dnsTxt,$domTxt,$dnsReach){$desiredDns=SplitList $dnsTxt;$domain=(SplitList $domTxt|Select-Object -First 1);$short=($fqdn -split '\.')[0];try{$cmd=@'
echo HOST=$(hostname -s)
echo FQDN=$(hostname -f)
echo DOMAIN=$(hostname -d)
echo DNS_BEGIN
(esxcli network ip dns server list 2>/dev/null | awk '/^[0-9]/{print $1}') || true
echo DNS_END
'@;$o=(EsxRetry $vmh $cmd 60 4).StdOut;$curHost=([regex]::Match($o,'(?m)^HOST=(.*)$')).Groups[1].Value.Trim();$curFqdn=([regex]::Match($o,'(?m)^FQDN=(.*)$')).Groups[1].Value.Trim();$curDom=([regex]::Match($o,'(?m)^DOMAIN=(.*)$')).Groups[1].Value.Trim();$block=([regex]::Match($o,'(?s)DNS_BEGIN\s*(.*?)\s*DNS_END')).Groups[1].Value;$curDns=@($block -split '[\r\n]+'|Where-Object{$_ -match '^\d+\.\d+\.\d+\.\d+$'});$okHost=(SafeLower $curHost)-eq(SafeLower $short);$okDom=(SafeLower $curDom)-eq(SafeLower $domain);$okFqdn=([string]::IsNullOrWhiteSpace($curFqdn) -or (SafeLower $curFqdn)-eq(SafeLower $fqdn) -or $curFqdn -eq $curHost);$dnsListOk=ContainsAll $desiredDns $curDns;$dnsFunctionalOk=($dnsReach -and $dnsReach.Status -eq 'Pass');$dnsOk=$dnsListOk -or ($curDns.Count -eq 0 -and $dnsFunctionalOk);$st=if($okHost -and $okDom -and $okFqdn -and $dnsOk){'Pass'}else{'Fail'};$note=if($curDns.Count -eq 0 -and $dnsFunctionalOk){'DNS list parse unavailable/blank; DNS functional query passed, so DNS verification accepted.'}else{''};return Check $st "Host=$curHost DesiredHost=$short; FQDN=$curFqdn DesiredFQDN=$fqdn; CurrentDNS=$(($curDns-join ',')); DesiredDNS=$(($desiredDns-join ',')); DNSListOk=$dnsListOk; DNSFunctionalOk=$dnsFunctionalOk; CurrentDomain=$curDom; DesiredDomain=$domain; $note"}catch{return Check 'Fail' $_.Exception.Message}}
function TestDnsResolution($fqdn){try{$f=@(Resolve-DnsName $fqdn -Type A -ErrorAction Stop|Where-Object{$_.IPAddress}|ForEach-Object{$_.IPAddress});if(!$f){return Check Fail 'Forward DNS returned no A records.'};$ptr=@();foreach($ip in $f){try{$ptr+=@(Resolve-DnsName $ip -Type PTR -ErrorAction Stop|Where-Object{$_.NameHost}|ForEach-Object{$_.NameHost})}catch{}};$ok=@($ptr|ForEach-Object{$_.TrimEnd('.').ToLowerInvariant()}|Where-Object{$_ -eq $fqdn.ToLowerInvariant()}).Count -gt 0;if($ok){Check Pass "Forward=$($f -join ','); PTR=$($ptr -join ','); lowercase hostname match confirmed."}else{Check Fail "Forward=$($f -join ','); PTR=$($ptr -join ','); PTR did not match lowercase FQDN."}}catch{Check Fail $_.Exception.Message}}
function TestDnsReach($vmh,$dnsTxt,$fqdn){$servers=@(SplitList $dnsTxt);$qfq=Q $fqdn;$quoted=($servers|ForEach-Object{Q $_}) -join ' ';$cmd=@"
for server in $quoted; do
 query=FAIL; tcp=UNKNOWN
 if command -v nc >/dev/null 2>&1; then if nc -z -w 3 `$server 53 >/dev/null 2>&1; then tcp=OPEN; else tcp=CLOSED; fi; fi
 if nslookup $qfq `$server >/tmp/dnscheck.out 2>&1; then query=OK; fi
 echo "DNS:`$server TCP53=`$tcp QUERY=`$query"
done
"@;try{$out=((EsxRetry $vmh $cmd 90 4).StdOut).Trim();$lines=@($out -split '[\r\n]+'|Where-Object{$_ -match '^DNS:'});$pass=@($lines|Where-Object{$_ -match 'QUERY=OK'}).Count -gt 0;Check $(if($pass){'Pass'}else{'Fail'}) $out}catch{Check Fail $_.Exception.Message}}
function RestartNtp($h){try{$svc=Get-VMHostService -VMHost $h|Where-Object{$_.Key -eq 'ntpd'}|Select-Object -First 1;if($svc){Set-VMHostService -HostService $svc -Policy On|Out-Null;try{Stop-VMHostService -HostService $svc -Confirm:$false -ErrorAction SilentlyContinue|Out-Null}catch{};SleepUi 3;Start-VMHostService -HostService $svc -Confirm:$false -ErrorAction SilentlyContinue|Out-Null;SleepUi 10;return $true}}catch{};try{EsxRetry $h '(/etc/init.d/ntpd restart || /etc/init.d/ntp restart || true)' 60 3|Out-Null;SleepUi 10;return $true}catch{return $false}}
function GetShellNtp($h){try{$cmd=@'
echo NTP_BEGIN
esxcli system ntp get 2>/dev/null | sed -n 's/.*Servers:[ ]*//p' | tr ',' '\n' | sed 's/^ *//;s/ *$//'
echo NTP_END
'@;$o=(EsxRetry $h $cmd 60 3).StdOut;$b=([regex]::Match($o,'(?s)NTP_BEGIN\s*(.*?)\s*NTP_END')).Groups[1].Value;@(Norm @($b -split '[\r\n]+'|Where-Object{$_.Trim()}))}catch{@()}}
function TestSetNtp($vmh,$ntpTxt,$apply){$desired=@(Norm (SplitList $ntpTxt));$changed=$false;$restarted=$false;try{$cur=@(Norm @(Get-VMHostNtpServer -VMHost $vmh -ErrorAction SilentlyContinue));if(!$cur){$cur=@(GetShellNtp $vmh)};$match=EqualList $desired $cur;if($apply -and !$match){Log "[$($vmh.Name)] Setting NTP servers to $(($desired-join','))";try{foreach($s in $cur){try{Remove-VMHostNtpServer -VMHost $vmh -NtpServer $s -Confirm:$false|Out-Null}catch{}};foreach($s in $desired){Add-VMHostNtpServer -VMHost $vmh -NtpServer $s -Confirm:$false|Out-Null}}catch{};$csv=$desired -join ',';EsxRetry $vmh "esxcli system ntp set -e true -s $(Q $csv) || true" 60 3|Out-Null;$restarted=RestartNtp $vmh;$changed=$true;$cur=@(Norm @(Get-VMHostNtpServer -VMHost $vmh -ErrorAction SilentlyContinue));if(!$cur){$cur=@(GetShellNtp $vmh)};$match=EqualList $desired $cur};$svc=$null;try{$svc=Get-VMHostService -VMHost $vmh|Where-Object{$_.Key -eq 'ntpd'}|Select-Object -First 1}catch{};$running=if($svc){[bool]$svc.Running}else{$apply};if($apply -and $match -and !$running){$restarted=RestartNtp $vmh;$running=$true};$sync=$false;$detail='';for($i=1;$i -le 10;$i++){Log "[$($vmh.Name)] Checking NTP sync attempt $i of 10...";try{$detail=((EsxRetry $vmh "(ntpq -pn 2>/dev/null || /usr/lib/vmware/ntp/bin/ntpq -pn 2>/dev/null || true)" 30 3).StdOut).Trim();if($detail -match '(?m)^\*' -or $detail -match '(?m)^[\+\- ]\S+\s+\S+\s+\d+\s+\w\s+\S+\s+\d+\s+[1-7]'){$sync=$true;break}}catch{$detail=$_.Exception.Message};if(!$sync -and $apply -and $i -eq 5){Log "[$($vmh.Name)] NTP has not selected/reached a peer by attempt 5. Restarting NTP service..." WARN;$restarted=RestartNtp $vmh};if($i -lt 10){SleepUi 15}};$cfg=if($match -and ($running -or $apply)){if($changed){'Remediated'}else{'Pass'}}else{'Fail'};[pscustomobject]@{Status=$cfg;Detail="CurrentNTP=$(($cur-join ',')); DesiredNTP=$(($desired-join ',')); ConfigMatch=$match; ServiceRunning=$running; Changed=$changed; ServiceRestarted=$restarted";SyncStatus=if($sync){'Pass'}else{'Fail'};SyncDetail="SyncPass=$sync; $detail"}}catch{[pscustomobject]@{Status='Fail';Detail=$_.Exception.Message;SyncStatus='Fail';SyncDetail='Skipped due to NTP config failure.'}}}
function TestTimeDrift($vmh){try{$scriptUtc=[DateTimeOffset]::UtcNow;$cmd=@'
echo ESX_EPOCH=$(date -u +%s)
echo ESX_UTC=$(date -u '+%Y-%m-%dT%H:%M:%SZ')
'@;$out=(EsxRetry $vmh $cmd 30 3).StdOut;$epoch=([regex]::Match($out,'(?m)^ESX_EPOCH=(\d+)')).Groups[1].Value;$hostText=([regex]::Match($out,'(?m)^ESX_UTC=(.*)$')).Groups[1].Value.Trim();if(!$epoch){throw "Unable to parse ESX time. Output=$out"};$hostUtc=[DateTimeOffset]::FromUnixTimeSeconds([int64]$epoch);$drift=[math]::Round(($hostUtc.UtcDateTime-$scriptUtc.UtcDateTime).TotalSeconds,2);[pscustomobject]@{Status='Pass';Detail="ScriptTimeUTC=$($scriptUtc.UtcDateTime.ToString('yyyy-MM-ddTHH:mm:ssZ')); HostTimeUTC=$($hostUtc.UtcDateTime.ToString('yyyy-MM-ddTHH:mm:ssZ')); HostReportedUTC=$hostText; DriftSeconds=$drift; AbsoluteDriftSeconds=$([math]::Abs($drift))";DriftSeconds=$drift}}catch{[pscustomobject]@{Status='Fail';Detail=$_.Exception.Message;DriftSeconds=$null}}}
function CertCheck($fqdn){try{$tcp=New-Object Net.Sockets.TcpClient($fqdn,443);$ssl=New-Object Net.Security.SslStream($tcp.GetStream(),$false,({$true}));$ssl.AuthenticateAsClient($fqdn);$cert=New-Object Security.Cryptography.X509Certificates.X509Certificate2($ssl.RemoteCertificate);$tcp.Close();$names=@($cert.GetNameInfo([Security.Cryptography.X509Certificates.X509NameType]::DnsName,$false));try{$san=$cert.Extensions|Where-Object{$_.Oid.FriendlyName -eq 'Subject Alternative Name'}|Select-Object -First 1;if($san){$names+=($san.Format($true)-split '[,\r\n]+'|ForEach-Object{($_ -replace 'DNS Name=','').Trim()})}}catch{};$fq=$fqdn.ToLowerInvariant();$ok=@($names|ForEach-Object{(SafeLower $_)}|Where-Object{$_ -eq $fq}).Count -gt 0;Check $(if($ok){'Pass'}else{'Fail'}) "RequiredLowercaseFQDN=$fq; Subject=$($cert.Subject); Names=$(@($names|Where-Object{$_}) -join ','); Expires=$($cert.NotAfter)"}catch{Check Fail $_.Exception.Message}}
function GenCert($vmh,$fqdn){try{EsxRetry $vmh '/sbin/generate-certificates' 180 3|Out-Null;Check Remediated "Ran /sbin/generate-certificates for lowercase FQDN $($fqdn.ToLowerInvariant()). Mandatory reboot will reload hostd/vpxa."}catch{Check Fail $_.Exception.Message}}
function IPv6($vmh,$apply){try{$evidenceCmd=@'
echo IPV6_EVIDENCE_BEGIN
echo --- esxcli network ip get ---
esxcli network ip get 2>/dev/null || true
echo --- esxcli network ip settings global list ---
esxcli network ip settings global list 2>/dev/null || true
echo --- esxcli network ip interface ipv6 address list ---
esxcli network ip interface ipv6 address list 2>/dev/null || true
echo --- advanced /Net/IPv6Enabled ---
esxcli system settings advanced list -o /Net/IPv6Enabled 2>/dev/null || true
echo IPV6_EVIDENCE_END
'@;$before=((EsxRetry $vmh $evidenceCmd 60 3).StdOut).Trim();$enabled=$false;if($before -match '(?im)IPv6\s+Enabled\s*:\s*true'){$enabled=$true};if($before -match '(?im)^\s*Int Value\s*:\s*1\s*$'){$enabled=$true};if($before -match '(?im)fe80:|inet6|IPv6 Address'){$enabled=$true};if($apply){$disableCmd=@'
echo "Requesting global IPv6 disable. A reboot is required for DCUI and management stack to reflect the final state."
esxcli network ip set --ipv6-enabled=false 2>&1 || true
esxcli system settings advanced set -o /Net/IPv6Enabled -i 0 2>&1 || true
'@;$disableOut=((EsxRetry $vmh $disableCmd 60 3).StdOut).Trim();$after='';try{$after=((EsxRetry $vmh $evidenceCmd 60 3).StdOut).Trim()}catch{$after="Post-disable evidence collection failed: $($_.Exception.Message)"};return Check 'Remediated' "IPv6 disable requested/enforced. Reboot required before DCUI final state changes. DetectedEnabledBefore=$enabled; DisableOutput=$disableOut; EvidenceBefore=$before; EvidenceAfter=$after"};return Check $(if($enabled){'Fail'}else{'Pass'}) $(if($enabled){"IPv6 appears enabled and Apply remediation is off. Evidence=$before"}else{"IPv6 disabled or no IPv6 evidence detected. Evidence=$before"})}catch{return Check Fail $_.Exception.Message}}
function Vsan($vmh,$clean){$check="esxcli storage core adapter rescan --all >/dev/null 2>&1; vdq -q 2>/dev/null || true; esxcli vsan storage list 2>/dev/null || true";if(!$clean){try{$out=((EsxRetry $vmh $check 180 3).StdOut).Trim();$bad=$out -match '"VSANUUID"\s*:\s*"[0-9a-fA-F-]{8,}|Disk Group UUID|CMMDS';Check $(if($bad){'Fail'}else{'Pass'}) $out}catch{Check Fail $_.Exception.Message}}else{$cmd=@'
esxcli storage core adapter rescan --all
vdq -q || true
for disk in $(esxcli storage core device list | grep -E "^(eui|naa)" | awk '{print $1}' | sort -u); do
 if ! esxcli storage core device list -d "$disk" | grep -qi "Is Boot Device: true"; then
  echo "----- Processing $disk -----"; esxcli vsan storage remove -u "$disk" 2>/dev/null || true; partedUtil mklabel /vmfs/devices/disks/$disk gpt; echo "Disk reset complete: $disk"
 else echo "Skipping boot device: $disk"; fi
done
esxcli storage core adapter rescan --all
vdq -q || true
'@;try{Check Remediated ((EsxRetry $vmh $cmd 600 3).StdOut)}catch{Check Fail $_.Exception.Message}}}
function RunHost($t){$server=$null;$vmh=$null;$h=SafeLower $t.TargetHost;$details=@();$reboot=$false;try{Log "[$h] Connecting with PowerCLI...";if(!(WaitTcp $h 443 120)){throw 'TCP/443 not reachable after 120 seconds.'};$server=ConnectRetry $h $t.Username $t.Password;$vmh=Get-VMHost -Server $server|Select-Object -First 1;if(!$vmh){throw 'No VMHost object returned.'};$script:CurrentShellUser=$t.Username;$script:CurrentShellPassword=$t.Password;EnableSsh $vmh;$dnsSet=SetHostDns $vmh $h $txtDns.Text $txtDomains.Text ([bool]$chkApply.IsChecked);Log "[$h] Hostname/DNS/Domain Set: $($dnsSet.Status)";$dnsfr=TestDnsResolution $h;Log "[$h] DNS Forward/Reverse: $($dnsfr.Status)";$dnsr=TestDnsReach $vmh $txtDns.Text $h;Log "[$h] DNS Reachability: $($dnsr.Status)";$dnsVerify=VerifyHostDns $vmh $h $txtDns.Text $txtDomains.Text $dnsr;Log "[$h] Hostname/DNS/Domain Verify: $($dnsVerify.Status)";$ntp=TestSetNtp $vmh $txtNtp.Text ([bool]$chkApply.IsChecked);Log "[$h] NTP Config: $($ntp.Status)";Log "[$h] NTP Sync: $($ntp.SyncStatus)";$td=TestTimeDrift $vmh;Log "[$h] Time Drift: $($td.Status) $($td.DriftSeconds) seconds";$vs=Vsan $vmh ([bool]$chkClean.IsChecked);Log "[$h] vSAN: $($vs.Status)";$certBefore=CertCheck $h;Log "[$h] Certificate Before Generation: $($certBefore.Status)";$certGen=if(([bool]$chkApply.IsChecked) -and $certBefore.Status -ne 'Pass'){GenCert $vmh $h}else{Check 'N/A' 'Certificate already matched lowercase FQDN or remediation disabled.'};$certSummary=if($certBefore.Status -eq 'Pass'){'Pass'}elseif($certGen.Status -eq 'Remediated'){'Remediated'}else{'Fail'};Log "[$h] Certificate Final: $certSummary";$ver=Check $(if((VerCmp $vmh.Version '9.1.0') -ge 0){'Pass'}else{'Fail'}) "Installed ESX version: $($vmh.Version); required: 9.1.0 or greater";$ip6=IPv6 $vmh ([bool]$chkApply.IsChecked);Log "[$h] IPv6: $($ip6.Status)";$rows=@(('Hostname/DNS/Domain Set',$dnsSet),('Hostname/DNS/Domain Verify',$dnsVerify),('DNS Forward/Reverse',$dnsfr),('DNS Reachability',$dnsr),('NTP Config',$ntp),('NTP Sync',[pscustomobject]@{Status=$ntp.SyncStatus;Detail=$ntp.SyncDetail}),('Time Drift',$td),('vSAN',$vs),('Certificate Before Generation',$certBefore),('Certificate Generation',$certGen),('ESXVersion',$ver),('IPv6',$ip6));foreach($r in $rows){$details+=[pscustomobject]@{Host=$h;Check=$r[0];Status=$r[1].Status;Detail=$r[1].Detail}};$statusList=@($dnsSet.Status,$dnsVerify.Status,$dnsfr.Status,$dnsr.Status,$ntp.Status,$ntp.SyncStatus,$td.Status,$vs.Status,$certSummary,$ver.Status,$ip6.Status);$overall=if(@($statusList|Where-Object{!(PassLike $_)}).Count -eq 0){'Pass'}else{'Fail'};$reboot=$true;[pscustomobject]@{Summary=[pscustomobject]@{Host=$h;FQDN=$h;HostnameDNSDomainSet=$dnsSet.Status;HostnameDNSDomainVerify=$dnsVerify.Status;DNSForwardReverse=$dnsfr.Status;DNSReachability=$dnsr.Status;NTPConfig=$ntp.Status;NTPSync=$ntp.SyncStatus;TimeDrift=$td.Status;TimeDriftSeconds=$td.DriftSeconds;vSAN=$vs.Status;Certificate=$certSummary;ESXVersion=$ver.Status;IPv6=$ip6.Status;Overall=$overall};Details=$details}}catch{Log "[$h] Connect/run failed: $($_.Exception.Message)" ERROR;[pscustomobject]@{Summary=[pscustomobject]@{Host=$h;FQDN=$h;HostnameDNSDomainSet='Fail';HostnameDNSDomainVerify='Fail';DNSForwardReverse='Fail';DNSReachability='Fail';NTPConfig='Fail';NTPSync='Fail';TimeDrift='Fail';TimeDriftSeconds=$null;vSAN='Fail';Certificate='Fail';ESXVersion='Fail';IPv6='Fail';Overall='Fail'};Details=@([pscustomobject]@{Host=$h;Check='Connect/Run';Status='Fail';Detail=$_.Exception.Message})}}finally{try{if($vmh){DisableSsh $vmh;if($reboot -and !$script:StopRequested){SleepUi 10;RebootHost $vmh $h}}}catch{};if($server){Disconnect-VIServer -Server $server -Force -Confirm:$false -ErrorAction SilentlyContinue|Out-Null}}}
function ExportReport($sum,$det){$p=Join-Path $script:RunDir ("VCF91-ESX-Validation-"+(Get-Date -Format yyyyMMdd-HHmmss)+'.xlsx');if(HasMod ImportExcel){Import-Module ImportExcel -ErrorAction SilentlyContinue;$sum|Export-Excel -Path $p -WorksheetName Hosts -AutoSize;$det|Export-Excel -Path $p -WorksheetName Details -AutoSize -Append}else{$p=$p.Replace('.xlsx','.csv');$sum|Export-Csv -NoTypeInformation -Path $p};$script:LastReportPath=$p;Log "Report saved: $p";$p}
function AddPoolName($n,$id=$null,$raw=$null){$n=([string]$n).Trim();if(!$n){return};foreach($i in @($cmbPool.Items)){if([string]$i.Content -eq $n){return}};$ci=New-Object System.Windows.Controls.ComboBoxItem;$ci.Content=$n;$ci.Tag=[pscustomobject]@{name=$n;id=$id;raw=$raw};[void]$cmbPool.Items.Add($ci)}
function InvokeJson($m,$u,$h=@{},$b=$null){$p=@{Method=$m;Uri=$u;Headers=$h;SkipCertificateCheck=$true;ErrorAction='Stop'};if($null-ne$b){$p.Body=($b|ConvertTo-Json -Depth 50);$p.ContentType='application/json'};$wr=Invoke-WebRequest @p;if($wr.Content){$wr.Content|ConvertFrom-Json}}
function ConnectPools{$fqdn=([string]$txtSddc.Text).Trim();$u=([string]$txtSddcUser.Text).Trim();$p=[string]$txtSddcPass.Password;if(!$fqdn -or !$u -or !$p){throw 'SDDC Manager FQDN, user, and password are required.'};$base=if($fqdn -match '^https?://'){$fqdn.TrimEnd('/')}else{"https://$fqdn"};$cmbPool.Items.Clear();$tok=InvokeJson POST "$base/v1/tokens" @{} @{username=$u;password=$p};$token=@($tok.accessToken,$tok.access_token,$tok.token,$tok.idToken,$tok.id_token)|Where-Object{$_}|Select-Object -First 1;if(!$token){throw 'Token response did not include a token.'};$np=InvokeJson GET "$base/v1/network-pools" @{Authorization="Bearer $token";Accept='application/json'};$items=@($np.elements);if(!$items){$items=@($np.networkPools)};if(!$items){$items=@($np.items)};foreach($pool in $items){$name=@($pool.name,$pool.networkPoolName,$pool.displayName)|Where-Object{$_}|Select-Object -First 1;$id=@($pool.id,$pool.networkPoolId,$pool.uuid)|Where-Object{$_}|Select-Object -First 1;if($name){AddPoolName $name $id $pool}};if($cmbPool.Items.Count){$cmbPool.SelectedIndex=0;Log "Loaded $($cmbPool.Items.Count) Network Pool name(s) from $base.";[System.Windows.MessageBox]::Show('Connected. Network Pool inventory loaded.','Connected')|Out-Null}else{throw 'No Network Pool names returned.'}}
function StorageCode($s){switch -Regex($s){'^vSAN OSA$'{'VSAN';break}'^vSAN Remote$'{'VSAN_REMOTE';break}'^vSAN ESA$'{'VSAN_ESA';break}'^vSAN Max$'{'VSAN_MAX';break}'^NFS$'{'NFS';break}'^VMFS on FC$'{'VMFS_FC';break}'^vVol$'{'VVOL';break}default{$s}}}
function GenJson{$targets=@(TargetRows);if(!$targets){throw 'No valid hosts.'};$np=if($cmbPool.SelectedItem -and $cmbPool.SelectedItem.Tag){[string]$cmbPool.SelectedItem.Tag.name}else{([string]$cmbPool.Text).Trim()};if(!$np){throw 'Select or type Network Pool Name.'};$storage=if($cmbStorage.SelectedItem){([System.Windows.Controls.ComboBoxItem]$cmbStorage.SelectedItem).Content.ToString()}else{'vSAN OSA'};$code=StorageCode $storage;$hosts=@();foreach($t in $targets){$hosts += [ordered]@{fqdn=$t.TargetHost;username=$t.Username;storageType=$code;password=$t.Password;networkPoolName=$np;vvolStorageProtocolType=''}};$path=Join-Path $script:RunDir ("bulk-commission-hosts-"+(Get-Date -Format yyyyMMdd-HHmmss)+'.json');([ordered]@{hosts=$hosts})|ConvertTo-Json -Depth 50|Out-File $path -Encoding UTF8;Log "Bulk commission JSON generated: $path";try{Start-Process notepad.exe $path}catch{Invoke-Item $path}}
$xaml=@'
<Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation" xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml" Title="VCF 9.1 ESX Host Validation and JSON Generator" Height="850" Width="1400" MinWidth="1040" WindowStartupLocation="CenterScreen" Background="#050A0D" Foreground="#E6E6E6" FontFamily="Segoe UI"><Window.Resources><Style TargetType="Button"><Setter Property="Background" Value="#D7DCE2"/><Setter Property="Foreground" Value="#111111"/><Setter Property="BorderBrush" Value="#7F8A96"/><Setter Property="Padding" Value="8,4"/><Setter Property="Margin" Value="4,3,4,3"/><Setter Property="Height" Value="28"/></Style><Style TargetType="TextBlock"><Setter Property="Foreground" Value="#E6E6E6"/><Setter Property="Margin" Value="0,4,8,4"/></Style><Style TargetType="TextBox"><Setter Property="Background" Value="#050A0D"/><Setter Property="Foreground" Value="#E6E6E6"/><Setter Property="BorderBrush" Value="#607D8B"/><Setter Property="Padding" Value="4"/><Setter Property="CaretBrush" Value="#E6E6E6"/></Style><Style TargetType="PasswordBox"><Setter Property="Background" Value="#050A0D"/><Setter Property="Foreground" Value="#E6E6E6"/><Setter Property="BorderBrush" Value="#607D8B"/><Setter Property="Padding" Value="4"/><Setter Property="CaretBrush" Value="#E6E6E6"/></Style><Style TargetType="ComboBox"><Setter Property="Height" Value="24"/></Style><Style TargetType="GroupBox"><Setter Property="Foreground" Value="#E6E6E6"/><Setter Property="Background" Value="#0A1418"/><Setter Property="BorderBrush" Value="#D7DCE2"/><Setter Property="Margin" Value="6"/><Setter Property="Padding" Value="8"/></Style><Style x:Key="GridText" TargetType="TextBlock"><Setter Property="Foreground" Value="#E6E6E6"/><Setter Property="Background" Value="#050A0D"/><Setter Property="Padding" Value="4,1,4,1"/></Style><Style x:Key="GridEdit" TargetType="TextBox"><Setter Property="Foreground" Value="#E6E6E6"/><Setter Property="Background" Value="#050A0D"/><Setter Property="BorderBrush" Value="#0078D7"/></Style><Style TargetType="DataGridColumnHeader"><Setter Property="Background" Value="#D7DCE2"/><Setter Property="Foreground" Value="#111111"/><Setter Property="FontWeight" Value="SemiBold"/></Style><Style TargetType="DataGrid"><Setter Property="Background" Value="#050A0D"/><Setter Property="Foreground" Value="#E6E6E6"/><Setter Property="RowBackground" Value="#050A0D"/><Setter Property="AlternatingRowBackground" Value="#050A0D"/><Setter Property="GridLinesVisibility" Value="All"/><Setter Property="HorizontalGridLinesBrush" Value="#607D8B"/><Setter Property="VerticalGridLinesBrush" Value="#607D8B"/><Setter Property="BorderBrush" Value="#607D8B"/><Setter Property="HeadersVisibility" Value="Column"/><Setter Property="RowHeaderWidth" Value="0"/></Style><Style TargetType="DataGridRow"><Setter Property="Background" Value="#050A0D"/><Setter Property="Foreground" Value="#E6E6E6"/></Style><Style TargetType="TabControl"><Setter Property="Background" Value="#050A0D"/></Style><Style TargetType="TabItem"><Setter Property="Foreground" Value="#111111"/><Setter Property="Padding" Value="8,3"/></Style></Window.Resources><Grid Margin="12" Background="#050A0D"><Grid.RowDefinitions><RowDefinition Height="Auto"/><RowDefinition Height="*"/><RowDefinition Height="180"/><RowDefinition Height="Auto"/></Grid.RowDefinitions><Grid Grid.Row="0"><Grid.ColumnDefinitions><ColumnDefinition Width="1*" MinWidth="440"/><ColumnDefinition Width="1.65*" MinWidth="560"/></Grid.ColumnDefinitions><GroupBox Header="Prerequisites" Grid.Column="0"><Grid><Grid.RowDefinitions><RowDefinition Height="42"/><RowDefinition Height="Auto"/></Grid.RowDefinitions><UniformGrid Columns="4"><StackPanel Orientation="Horizontal"><TextBlock Text="PowerShell:"/><TextBlock x:Name="lblPS"/></StackPanel><StackPanel Orientation="Horizontal"><TextBlock Text="VCF PowerCLI:"/><TextBlock x:Name="lblPCLI"/></StackPanel><StackPanel Orientation="Horizontal"><TextBlock Text="ImportExcel:"/><TextBlock x:Name="lblExcel"/></StackPanel><StackPanel Orientation="Horizontal"><TextBlock Text="Posh-SSH:"/><TextBlock x:Name="lblSsh"/></StackPanel></UniformGrid><StackPanel Grid.Row="1" Orientation="Horizontal"><Button x:Name="btnRecheck" Content="Recheck"/><Button x:Name="btnInstallPowerCLI" Content="Install VCF PowerCLI"/><Button x:Name="btnInstallExcel" Content="Install ImportExcel"/><Button x:Name="btnInstallSSH" Content="Install Posh-SSH"/></StackPanel></Grid></GroupBox><GroupBox Header="Desired ESX Configuration" Grid.Column="1"><Grid Margin="6"><Grid.ColumnDefinitions><ColumnDefinition Width="110"/><ColumnDefinition Width="2*"/><ColumnDefinition Width="24"/><ColumnDefinition Width="110"/><ColumnDefinition Width="1.15*"/></Grid.ColumnDefinitions><Grid.RowDefinitions><RowDefinition Height="32"/><RowDefinition Height="32"/><RowDefinition Height="30"/></Grid.RowDefinitions><TextBlock Text="DNS servers" VerticalAlignment="Center"/><TextBox x:Name="txtDns" Grid.Column="1" VerticalAlignment="Center"/><TextBlock Grid.Column="3" Text="Search domains" Margin="12,4,8,4" VerticalAlignment="Center"/><TextBox x:Name="txtDomains" Grid.Column="4" VerticalAlignment="Center"/><TextBlock Grid.Row="1" Text="NTP servers" VerticalAlignment="Center"/><TextBox x:Name="txtNtp" Grid.Row="1" Grid.Column="1" VerticalAlignment="Center"/><StackPanel Grid.Row="2" Grid.Column="1" Grid.ColumnSpan="4" Orientation="Horizontal" Margin="0,4,0,0"><CheckBox x:Name="chkApply" Content="Apply remediation" Foreground="#E6E6E6" IsChecked="True" Margin="0,0,36,0"/><CheckBox x:Name="chkClean" Content="Clean vSAN residue" Foreground="#E6E6E6"/></StackPanel></Grid></GroupBox></Grid><TabControl Grid.Row="1" Margin="0,8,0,0"><TabItem Header="Validation"><Grid Margin="8" Background="#050A0D"><Grid.RowDefinitions><RowDefinition Height="*"/><RowDefinition Height="Auto"/></Grid.RowDefinitions><DataGrid x:Name="gridValidation" AutoGenerateColumns="False" CanUserAddRows="False"><DataGrid.Columns><DataGridTextColumn Header="Host FQDN" Binding="{Binding TargetHost}" Width="2*" ElementStyle="{StaticResource GridText}" EditingElementStyle="{StaticResource GridEdit}"/><DataGridTextColumn Header="User Name" Binding="{Binding Username}" Width="*" ElementStyle="{StaticResource GridText}" EditingElementStyle="{StaticResource GridEdit}"/><DataGridTextColumn Header="Password" Binding="{Binding Password}" Width="*" ElementStyle="{StaticResource GridText}" EditingElementStyle="{StaticResource GridEdit}"/></DataGrid.Columns></DataGrid><StackPanel Grid.Row="1" Orientation="Horizontal" Margin="0,4,0,0"><Button x:Name="btnRun" Content="Run Readiness"/><Button x:Name="btnAdd" Content="Add Host"/><Button x:Name="btnRemove" Content="Remove Selected"/><Button x:Name="btnLoad" Content="Load CSV"/><Button x:Name="btnSave" Content="Save CSV"/><Button x:Name="btnExample" Content="Download Example CSV"/></StackPanel></Grid></TabItem><TabItem Header="Results"><DataGrid x:Name="gridResults" AutoGenerateColumns="True" IsReadOnly="True"/></TabItem><TabItem Header="JSON Generator"><Grid Margin="8" Background="#050A0D"><GroupBox Header="Bulk Commission JSON Settings"><Grid><Grid.ColumnDefinitions><ColumnDefinition Width="160"/><ColumnDefinition Width="*"/></Grid.ColumnDefinitions><Grid.RowDefinitions><RowDefinition Height="34"/><RowDefinition Height="34"/><RowDefinition Height="34"/><RowDefinition Height="34"/><RowDefinition Height="34"/><RowDefinition Height="Auto"/></Grid.RowDefinitions><TextBlock Text="SDDC Manager FQDN"/><TextBox x:Name="txtSddc" Grid.Column="1"/><TextBlock Grid.Row="1" Text="User"/><TextBox x:Name="txtSddcUser" Grid.Row="1" Grid.Column="1" Text="administrator@vsphere.local"/><TextBlock Grid.Row="2" Text="Password"/><PasswordBox x:Name="txtSddcPass" Grid.Row="2" Grid.Column="1"/><TextBlock Grid.Row="3" Text="Network Pool Name"/><ComboBox x:Name="cmbPool" Grid.Row="3" Grid.Column="1" IsEditable="True"/><TextBlock Grid.Row="4" Text="Storage Type"/><ComboBox x:Name="cmbStorage" Grid.Row="4" Grid.Column="1" SelectedIndex="0"><ComboBoxItem>vSAN OSA</ComboBoxItem><ComboBoxItem>vSAN Remote</ComboBoxItem><ComboBoxItem>vSAN ESA</ComboBoxItem><ComboBoxItem>vSAN Max</ComboBoxItem><ComboBoxItem>NFS</ComboBoxItem><ComboBoxItem>VMFS on FC</ComboBoxItem><ComboBoxItem>vVol</ComboBoxItem></ComboBox><StackPanel Grid.Row="5" Grid.ColumnSpan="2" Orientation="Horizontal" HorizontalAlignment="Center"><Button x:Name="btnConnect" Content="Connect" Width="120"/><Button x:Name="btnJson" Content="Generate JSON" Width="130"/></StackPanel></Grid></GroupBox></Grid></TabItem></TabControl><GroupBox Grid.Row="2" Header="Log"><TextBox x:Name="txtLog" IsReadOnly="True" TextWrapping="Wrap" VerticalScrollBarVisibility="Auto" HorizontalScrollBarVisibility="Auto" FontFamily="Consolas" FontSize="12" Background="#050A0D" Foreground="#E6E6E6"/></GroupBox><StackPanel Grid.Row="3" Orientation="Horizontal" HorizontalAlignment="Center"><Button x:Name="btnOpen" Content="Open Report"/><Button x:Name="btnClose" Content="Close"/><Button x:Name="btnStop" Content="Stop" IsEnabled="False"/></StackPanel></Grid></Window>
'@
$w=[Windows.Markup.XamlReader]::Parse($xaml)
foreach($n in 'lblPS','lblPCLI','lblExcel','lblSsh','btnRecheck','btnInstallPowerCLI','btnInstallExcel','btnInstallSSH','txtDns','txtDomains','txtNtp','chkApply','chkClean','gridValidation','gridResults','btnAdd','btnRemove','btnLoad','btnSave','btnExample','txtLog','btnRun','btnStop','btnOpen','btnClose','txtSddc','txtSddcUser','txtSddcPass','btnConnect','cmbPool','cmbStorage','btnJson'){Set-Variable -Scope Script -Name $n -Value $w.FindName($n)}
$script:Targets=New-Object System.Collections.ObjectModel.ObservableCollection[object];$script:Rows=New-Object System.Collections.ObjectModel.ObservableCollection[object];$gridValidation.ItemsSource=$script:Targets;$gridResults.ItemsSource=$script:Rows;1..2|ForEach-Object{$script:Targets.Add([pscustomobject]@{TargetHost='';Username='root';Password=''})|Out-Null}
$btnRecheck.Add_Click({Prereq})
$btnInstallPowerCLI.Add_Click({Start-Process powershell -ArgumentList '-NoExit','-Command','Install-Module -Name VCF.PowerCLI -Scope CurrentUser -Force -AllowClobber -SkipPublisherCheck'})
$btnInstallExcel.Add_Click({Start-Process powershell -ArgumentList '-NoExit','-Command','Install-Module ImportExcel -Scope CurrentUser -Force'})
$btnInstallSSH.Add_Click({Start-Process powershell -ArgumentList '-NoExit','-Command','Install-Module Posh-SSH -Scope CurrentUser -Force'})
$btnOpen.Add_Click({if($script:LastReportPath -and (Test-Path $script:LastReportPath)){Invoke-Item $script:LastReportPath}else{[System.Windows.MessageBox]::Show('No report has been generated yet.','No report')|Out-Null}})
$btnClose.Add_Click({$w.Close()})
$btnStop.Add_Click({$script:StopRequested=$true;$btnStop.IsEnabled=$false;Log 'Stop requested by operator.' WARN})
$btnAdd.Add_Click({$script:Targets.Add([pscustomobject]@{TargetHost='';Username='root';Password=''})|Out-Null})
$btnRemove.Add_Click({foreach($i in @($gridValidation.SelectedItems)){$script:Targets.Remove($i)|Out-Null}})
$btnLoad.Add_Click({$dlg=New-Object Microsoft.Win32.OpenFileDialog;$dlg.Filter='CSV files (*.csv)|*.csv|All files (*.*)|*.*';if($dlg.ShowDialog()){$script:Targets.Clear();Import-Csv $dlg.FileName|ForEach-Object{$script:Targets.Add([pscustomobject]@{TargetHost=$_.TargetHost;Username=if($_.Username){$_.Username}else{'root'};Password=$_.Password})|Out-Null};Log "Loaded $($script:Targets.Count) validation row(s)."}})
$btnSave.Add_Click({$p=Join-Path $script:RunDir 'validation-targets.csv';TargetRows|Export-Csv -NoTypeInformation -Path $p;Log "Saved validation targets: $p"})
$btnExample.Add_Click({$p=Join-Path $script:RunDir 'example-validation-targets.csv';@([pscustomobject]@{TargetHost='pod01esx12.corp.example.com';Username='root';Password='example'})|Export-Csv -NoTypeInformation -Path $p;Log "Example CSV saved: $p"})
$btnConnect.Add_Click({try{ConnectPools}catch{Log $_.Exception.Message ERROR;[System.Windows.MessageBox]::Show($_.Exception.Message,'Network Pool connect failed')|Out-Null}})
$btnJson.Add_Click({try{GenJson;[System.Windows.MessageBox]::Show('JSON generated and opened.','JSON generated')|Out-Null}catch{Log $_.Exception.Message ERROR;[System.Windows.MessageBox]::Show($_.Exception.Message,'Generate JSON failed')|Out-Null}})
$btnRun.Add_Click({try{if($script:IsRunning){return};ValidateInputs;if($chkClean.IsChecked){$ans=[System.Windows.MessageBox]::Show('Clean vSAN residue is destructive. It removes vSAN membership and resets non-boot disks to GPT. Boot disks are skipped. Continue?','Destructive vSAN Cleanup','YesNo','Warning');if($ans -ne 'Yes'){return}};$script:IsRunning=$true;$script:StopRequested=$false;$btnRun.IsEnabled=$false;$btnStop.IsEnabled=$true;$script:Rows.Clear();$sum=@();$det=@();$targets=TargetRows;Log "Validation rows committed. Filtered target count=$($targets.Count). Hosts=$(@($targets|ForEach-Object{$_.TargetHost})-join ',')";foreach($t in $targets){CheckStop;$r=RunHost $t;$sum+=$r.Summary;$det+=$r.Details;$script:Rows.Add($r.Summary)|Out-Null;$gridResults.Items.Refresh();DoEvents};$rep=ExportReport $sum $det;Log "Readiness complete. Report=$rep"}catch{Log $_.Exception.Message ERROR;[System.Windows.MessageBox]::Show($_.Exception.Message,'Run Readiness failed')|Out-Null}finally{$script:IsRunning=$false;$btnStop.IsEnabled=$false;$btnRun.IsEnabled=$true;Prereq}})
Prereq
EnsureToolSelfSignedCertificate
Log "Script started. Output: $script:RunDir"
$w.ShowDialog()|Out-Null
